import { Vex } from '@vex_dev/sdk';
import { MastraAgent } from 'mastra';

const vex = new Vex({
  projectId: 'csirt-prod',
  policyId: 'nist-cybersecurity-agent'
});

const agent = new MastraAgent({
  workflow: async (input, context) => {
    // Vex middleware validates threat intel before LLM
    const validatedInput = await vex.check({
      data: input,
      rules: ['no_threat_leakage', 'cve_verification'],
      context: { sensitivity: 'critical' }
    });

    const result = await workflowStep(validatedInput);
    return await vex.approveAction(result, { requiresHuman: true });
  }
});

import { VexGuard } from '@vex_dev/sdk';

const humanApprovalGuard = new VexGuard({
  name: 'critical-action-approval',
  rules: [
    'human_approval_required',
    'no_auto_remediation'
  ]
});

// In Mastra tool integration
agent.addTool({
  name: 'isolateHost',
  execute: async (host: string) => {
    const decision = await humanApprovalGuard.evaluate({
      action: 'isolate',
      target: host,
      riskScore: 9.2,
      evidence: 'suspicious_beaconing'
    });

    if (!decision.approved) {
      throw new Error('Human approval required');
    }
    return await isolateHost(host);
  }
});

import { Vex } from '@vex_dev/sdk';

const cveValidator = async (retrievedContext: any) => {
  const vex = new Vex({ projectId: 'csirt-prod' });

  const validation = await vex.verify({
    data: retrievedContext,
    against: 'cve_database',
    rules: ['cve_status_valid', 'no_stale_intel'],
    timeout: 5000
  });

  if (!validation.valid) {
    console.warn('Blocked stale CVE reference:', validation.issues);
    return { ...retrievedContext, verified: false };
  }

  return retrievedContext;
};

// Mastra memory hook
agent.on('memoryRetrieve', cveValidator);
